 1→import AppKit
 2→
 3→/// 連續捲動模式中的單一圖片 slot view
 4→/// 使用 layer-backed GPU 渲染 (wantsUpdateLayer = true)
 5→class ImageSlotView: NSView {
 6→    // MARK: - Properties
 7→    var imageIndex: Int = -1
 8→    private var cachedCGImage: CGImage?
 9→    private var loadTask: Task<Void, Never>?
10→
11→    // MARK: - Initialization
12→    override init(frame frameRect: NSRect) {
13→        super.init(frame: frameRect)
14→        wantsLayer = true
15→        layerContentsRedrawPolicy = .onSetNeedsDisplay
16→        layer?.contentsGravity = .resize
17→    }
18→
19→    required init?(coder: NSCoder) {
20→        fatalError("init(coder:) not supported")
21→    }
22→
23→    // MARK: - Layer-backed Rendering
24→    override var wantsUpdateLayer: Bool { true }
25→
26→    override func updateLayer() {
27→        guard let layer else { return }
28→        layer.contents = cachedCGImage
29→        layer.contentsScale = window?.backingScaleFactor ?? 2.0
30→    }
31→
32→    // MARK: - Backing Properties Change
33→    override func viewDidChangeBackingProperties() {
34→        super.viewDidChangeBackingProperties()
35→        needsDisplay = true
36→    }
37→
38→    // MARK: - Configuration
39→    func setImage(_ image: NSImage?) {
